package com.chaobo.scm.supplier.application.item;
import com.chaobo.scm.supplier.application.shared.OutboxRepository;import com.chaobo.scm.supplier.domain.item.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.springframework.stereotype.Service;
@Service public class SupplierItemMasterDataStatusService {private final SupplierItemRepository repo;private final OutboxRepository outbox;private final IdentifierGenerator ids;public SupplierItemMasterDataStatusService(SupplierItemRepository repo,OutboxRepository outbox,IdentifierGenerator ids){this.repo=repo;this.outbox=outbox;this.ids=ids;}public void pauseBySupplier(long supplierId,String reason){for(var item:repo.findAvailableBySupplier(supplierId))pause(item,reason);}public void pauseBySku(String skuCode,String reason){for(var item:repo.findAvailableBySku(skuCode))pause(item,reason);}private void pause(SupplierItemAggregate item,String reason){item.pause(reason,0,ids);repo.save(item,0);outbox.saveAll(item.pullEvents());}}
